#include <bits/stdc++.h>
using namespace std;

int a[8];
bitset<60004> f;

int main(){
    while(cin>>a[1]>>a[2]>>a[3]>>a[4]>>a[5]>>a[6],a[1]+a[2]+a[3]+a[4]+a[5]+a[6]){
        f.reset();
        int sum=a[1]*1+a[2]*2+a[3]*3+a[4]*4+a[5]*5+a[6]*6;
        if(sum%2){
            puts("Can't");
            continue;
        }
        f[0]=1;
        for(int i=1;i<=6;i++){
            int tmp=a[i],num=1;
            while(num<=tmp){
                f|=f<<(num*i);
                tmp-=num,num*=2;
            }
            if(tmp)
                f|=f<<(tmp*i);
        }
        if(f[sum/2])
            puts("Can");
        else
            puts("Can't");
    }
    return 0;
}
